  1→import React from 'react';
  2→import { BarChart3, Radio, Globe, Bell } from 'lucide-react';
  3→
  4→interface StatsOverviewProps {
  5→  stats: {
  6→    aeoScore: number | null;
  7→    citationCount: number;
  8→    languagesAnalyzed: number;
  9→    activeAlerts: number;
 10→  };
 11→}
 12→
 13→const cards = [
 14→  {
 15→    key: 'aeoScore',
 16→    label: 'Score AEO',
 17→    suffix: '/100',
 18→    icon: BarChart3,
 19→    iconBg: 'bg-blue-500/10',
 20→    iconColor: 'text-blue-400',
 21→  },
 22→  {
 23→    key: 'citationCount',
 24→    label: 'Citations IA',
 25→    suffix: '',
 26→    icon: Radio,
 27→    iconBg: 'bg-emerald-500/10',
 28→    iconColor: 'text-emerald-400',
 29→  },
 30→  {
 31→    key: 'languagesAnalyzed',
 32→    label: 'Langues',
 33→    suffix: '/10',
 34→    icon: Globe,
 35→    iconBg: 'bg-purple-500/10',
 36→    iconColor: 'text-purple-400',
 37→  },
 38→  {
 39→    key: 'activeAlerts',
 40→    label: 'Alertes',
 41→    suffix: '',
 42→    icon: Bell,
 43→    iconBg: 'bg-amber-500/10',
 44→    iconColor: 'text-amber-400',
 45→  },
 46→] as const;
 47→
 48→const StatsOverview: React.FC<StatsOverviewProps> = ({ stats }) => {
 49→  const hasData = stats.aeoScore !== null || stats.citationCount > 0 || stats.languagesAnalyzed > 0 || stats.activeAlerts > 0;
 50→
 51→  return (
 52→    <div>
 53→      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
 54→        {cards.map((card) => {
 55→          const Icon = card.icon;
 56→          const value = stats[card.key];
 57→          const isNull = value === null || value === undefined;
 58→
 59→          return (
 60→            <div
 61→              key={card.key}
 62→              className="relative bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 hover:bg-white/[0.05] hover:border-white/[0.08] transition-all duration-200"
 63→            >
 64→              <p className="text-[12px] uppercase tracking-wider text-zinc-500 font-medium">
 65→                {card.label}
 66→              </p>
 67→              <div className="flex items-baseline mt-2">
 68→                {isNull ? (
 69→                  <div>
 70→                    <span className="text-2xl font-bold text-zinc-600 tracking-tight">&mdash;</span>
 71→                    <p className="text-[12px] text-zinc-600 mt-1">Pas encore d'audit</p>
 72→                  </div>
 73→                ) : (
 74→                  <>
 75→                    <span className="text-2xl font-bold text-white tracking-tight">{value}</span>
 76→                    {card.suffix && (
 77→                      <span className="text-lg text-zinc-500 font-normal">{card.suffix}</span>
 78→                    )}
 79→                  </>
 80→                )}
 81→              </div>
 82→              <div className={`absolute top-4 right-4 w-8 h-8 rounded-lg ${card.iconBg} flex items-center justify-center`}>
 83→                <Icon className={`w-4 h-4 ${card.iconColor}`} />
 84→              </div>
 85→            </div>
 86→          );
 87→        })}
 88→      </div>
 89→
 90→      {!hasData && (
 91→        <p className="text-zinc-500 text-[14px] text-center py-4">
 92→          Lancez votre premier audit pour voir vos statistiques ici.
 93→        </p>
 94→      )}
 95→    </div>
 96→  );
 97→};
 98→
 99→export default StatsOverview;
