  1→import React, { useState, useRef, useEffect } from 'react';
  2→import { Search } from 'lucide-react';
  3→
  4→const CommandPalettePanel: React.FC<{ onClose: () => void; onNavigate: (view: string) => void }> = ({ onClose, onNavigate }) => {
  5→  const [query, setQuery] = useState('');
  6→  const inputRef = useRef<HTMLInputElement>(null);
  7→
  8→  useEffect(() => {
  9→    setTimeout(() => inputRef.current?.focus(), 100);
 10→  }, []);
 11→
 12→  const commands = [
 13→    { id: 'analyze', label: 'Nouvel Audit AEO', icon: '🔍', category: 'Navigation' },
 14→    { id: 'dashboard', label: 'Dashboard Pro', icon: '📊', category: 'Navigation' },
 15→    { id: 'projects', label: 'Monitoring AEO', icon: '📈', category: 'Navigation' },
 16→    { id: 'generative-tools', label: 'Outils Génératifs', icon: '✨', category: 'Outils' },
 17→    { id: 'smc-studio', label: 'SMC Studio', icon: '✏️', category: 'Outils' },
 18→    { id: 'content-writer', label: 'AI Content Writer', icon: '📝', category: 'Outils' },
 19→    { id: 'reputation', label: 'Réputation IA', icon: '🛡️', category: 'Outils' },
 20→    { id: 'source-of-truth', label: 'Source of Truth', icon: '📄', category: 'Outils' },
 21→    { id: 'schema-org', label: 'Schema.org Generator', icon: '🔧', category: 'Outils' },
 22→    { id: 'robots-txt', label: 'Robots.txt Optimizer', icon: '🤖', category: 'Outils' },
 23→    { id: 'bot-tracking', label: 'Suivi Bots IA', icon: '👁️', category: 'Outils' },
 24→    { id: 'blog-optimizer', label: 'Blog Optimiser', icon: '📰', category: 'Outils' },
 25→    { id: 'ai-response-layer', label: 'AI Response Layer', icon: '🧩', category: 'Outils' },
 26→    { id: 'llms-txt', label: 'Générateur llms.txt', icon: '📋', category: 'Outils' },
 27→    { id: 'answer-first-audit', label: 'Audit Answer-First', icon: '🎯', category: 'Outils' },
 28→    { id: 'ai-citation-simulator', label: 'Simulateur Citation IA', icon: '🤖', category: 'Outils' },
 29→    { id: 'eeat-builder', label: 'E-E-A-T Builder', icon: '🏆', category: 'Outils' },
 30→    { id: 'ai-monitoring', label: 'Monitoring IA', icon: '📡', category: 'Navigation' },
 31→    { id: 'directory', label: 'Annuaire Indexé', icon: '📚', category: 'Navigation' },
 32→    { id: 'recharge', label: 'GTO Gas Station', icon: '⛽', category: 'Navigation' },
 33→    { id: 'clients', label: 'Base Clients', icon: '👥', category: 'Navigation' },
 34→    { id: 'mission-orders', label: 'Ordres de Mission', icon: '📋', category: 'Navigation' },
 35→    { id: 'alerts', label: 'Alertes AEO', icon: '🔔', category: 'Navigation' },
 36→    { id: 'account', label: 'Compte & Plan', icon: '👤', category: 'Navigation' },
 37→    { id: 'affiliation', label: 'Programme Partenaire', icon: '🤝', category: 'Navigation' },
 38→    { id: 'integrations', label: 'Intégrations GA4 & Search Console', icon: '🔗', category: 'Navigation' },
 39→    { id: 'api-developer', label: 'API Developer Hub', icon: '⚡', category: 'Outils' },
 40→  ];
 41→
 42→  const filtered = query
 43→    ? commands.filter(c => c.label.toLowerCase().includes(query.toLowerCase()))
 44→    : commands;
 45→
 46→  const grouped = filtered.reduce((acc, cmd) => {
 47→    if (!acc[cmd.category]) acc[cmd.category] = [];
 48→    acc[cmd.category].push(cmd);
 49→    return acc;
 50→  }, {} as Record<string, typeof commands>);
 51→
 52→  // Highlight matched text in label
 53→  const highlightMatch = (label: string) => {
 54→    if (!query) return <span>{label}</span>;
 55→    const lowerLabel = label.toLowerCase();
 56→    const lowerQuery = query.toLowerCase();
 57→    const idx = lowerLabel.indexOf(lowerQuery);
 58→    if (idx === -1) return <span>{label}</span>;
 59→    return (
 60→      <span>
 61→        {label.slice(0, idx)}
 62→        <span className="text-purple-400 font-semibold">{label.slice(idx, idx + query.length)}</span>
 63→        {label.slice(idx + query.length)}
 64→      </span>
 65→    );
 66→  };
 67→
 68→  return (
 69→    <div
 70→      className="relative w-full max-w-[560px] bg-[#13131d] border border-white/[0.1] rounded-2xl shadow-2xl shadow-black/50 overflow-hidden"
 71→      onClick={(e) => e.stopPropagation()}
 72→    >
 73→      <div className="flex items-center gap-3 px-5 py-4 border-b border-white/[0.08]">
 74→        <Search size={18} className="text-gray-500 shrink-0" />
 75→        <input
 76→          ref={inputRef}
 77→          type="text"
 78→          value={query}
 79→          onChange={(e) => setQuery(e.target.value)}
 80→          placeholder="Rechercher une page, un outil..."
 81→          className="flex-1 bg-transparent text-white text-[15px] placeholder-gray-600 outline-none"
 82→        />
 83→        <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">ESC</kbd>
 84→      </div>
 85→      <div className="max-h-[340px] overflow-y-auto py-2">
 86→        {Object.keys(grouped).length === 0 ? (
 87→          <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun résultat pour &ldquo;{query}&rdquo;</div>
 88→        ) : (
 89→          Object.entries(grouped).map(([category, cmds]) => (
 90→            <div key={category}>
 91→              <div className="px-5 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-wider">{category}</div>
 92→              {cmds.map((cmd) => (
 93→                <button
 94→                  key={cmd.id}
 95→                  onClick={() => onNavigate(cmd.id)}
 96→                  className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-white/[0.04] transition-colors group"
 97→                >
 98→                  <span className="text-base">{cmd.icon}</span>
 99→                  <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{highlightMatch(cmd.label)}</span>
100→                </button>
101→              ))}
102→            </div>
103→          ))
104→        )}
105→      </div>
106→      <div className="px-5 py-3 border-t border-white/[0.06] flex items-center justify-between text-[11px] text-gray-600">
107→        <div className="flex items-center gap-3">
108→          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">↑↓</kbd> naviguer</span>
109→          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">↵</kbd> ouvrir</span>
110→        </div>
111→        <span>CitedBy.ai</span>
112→      </div>
113→    </div>
114→  );
115→};
116→
117→export default CommandPalettePanel;
