  7→import { BarChart3, TrendingUp, Sparkles } from 'lucide-react';
  8→
  9→// ═══════════════════════════════════════════════════════════
 10→// ENGINE TYPES & CATEGORY-LEVEL BIASES
 11→// ═══════════════════════════════════════════════════════════
 12→
 13→type EngineId = 'chatgpt' | 'perplexity' | 'gemini' | 'claude' | 'copilot' | 'ai_overviews';
 14→
 15→// Category-level engine biases — derived from averaging
 16→// the 50 per-criterion weights in config/engine-weights.ts
 17→// by their closest category grouping.
 18→const CATEGORY_ENGINE_BIAS: Record<string, Record<EngineId, number>> = {
 19→  technical:       { chatgpt: 0.7, perplexity: 1.0, gemini: 1.1, claude: 0.5, copilot: 1.1, ai_overviews: 1.1 },
