 41→// ═══════════════════════════════════════════════════════════
 42→// CITATION RATE ESTIMATION
 43→// ═══════════════════════════════════════════════════════════
 44→
 45→function estimateCitationRate(aeoScore: number): number {
 46→  if (aeoScore <= 30) return Math.round(aeoScore * 0.3);
 47→  if (aeoScore <= 50) return Math.round(10 + (aeoScore - 30) * 0.8);
 48→  if (aeoScore <= 70) return Math.round(26 + (aeoScore - 50) * 1.2);
 49→  if (aeoScore <= 85) return Math.round(50 + (aeoScore - 70) * 1.5);
 50→  return Math.round(73 + (aeoScore - 85) * 1.8);
 51→}
