 53→// ═══════════════════════════════════════════════════════════
 54→// PROPS
 55→// ═══════════════════════════════════════════════════════════
 56→
 57→interface ScoreProjectionProps {
 58→  categories: Record<string, CategoryScore>;
 59→  recommendations: Recommendation[];
 60→  selectedSolutions: Set<string>;
 61→  globalScore: number;
 62→}
 63→
 64→// ═══════════════════════════════════════════════════════════
 65→// PROJECTION CALCULATION
 66→// ═══════════════════════════════════════════════════════════
 67→
 68→function calculateProjection(
 69→  categories: Record<string, CategoryScore>,
 70→  recommendations: Recommendation[],
 71→  selectedSolutions: Set<string>,
 72→  globalScore: number,
 73→) {
 74→  // Build reverse map: category display name → category ID
 75→  const reverseCategoryMap: Record<string, string> = {};
 76→  for (const [catId, cat] of Object.entries(categories)) {
 77→    reverseCategoryMap[cat.name] = catId;
 78→  }
 79→
 80→  // Count how many selected recommendations per category
 81→  const fixedPerCategory: Record<string, number> = {};
 82→  for (const rec of recommendations) {
 83→    if (selectedSolutions.has(rec.id)) {
 84→      const catId = reverseCategoryMap[rec.category];
 85→      if (catId) {
 86→        fixedPerCategory[catId] = (fixedPerCategory[catId] || 0) + 1;
 87→      }
 88→    }
 89→  }
 90→
 91→  // Calculate projected category scores
 92→  const projectedCategoryScores: Record<string, number> = {};
 93→  for (const [catId, cat] of Object.entries(categories)) {
 94→    const totalCriteria = cat.items.length;
 95→    const passedCount = cat.items.filter(i => i.status === 'success').length;
 96→    const failedCount = totalCriteria - passedCount;
 97→    // Can't fix more than what's actually failed
 98→    const fixed = Math.min(fixedPerCategory[catId] || 0, failedCount);
 99→    const newPassed = passedCount + fixed;
100→    projectedCategoryScores[catId] = Math.round((newPassed / totalCriteria) * 100);
101→  }
102→
103→  // Projected global score = average of all category scores
104→  const catIds = Object.keys(categories);
105→  const projectedGlobalScore = catIds.length > 0
106→    ? Math.round(catIds.reduce((sum, id) => sum + projectedCategoryScores[id], 0) / catIds.length)
107→    : globalScore;
108→
109→  // Engine scores — weighted average of category scores
110→  const currentEngineScores: Record<EngineId, number> = { chatgpt: 0, perplexity: 0, gemini: 0, claude: 0, copilot: 0, ai_overviews: 0 };
111→  const projectedEngineScores: Record<EngineId, number> = { chatgpt: 0, perplexity: 0, gemini: 0, claude: 0, copilot: 0, ai_overviews: 0 };
112→
113→  for (const engine of ['chatgpt', 'perplexity', 'gemini', 'claude', 'copilot', 'ai_overviews'] as EngineId[]) {
114→    let currentWeightedSum = 0;
115→    let projectedWeightedSum = 0;
116→    let totalWeight = 0;
117→
118→    for (const [catId, cat] of Object.entries(categories)) {
119→      const bias = CATEGORY_ENGINE_BIAS[catId]?.[engine] ?? 1.0;
120→      currentWeightedSum += cat.score * bias;
121→      projectedWeightedSum += projectedCategoryScores[catId] * bias;
122→      totalWeight += bias;
123→    }
124→
125→    currentEngineScores[engine] = totalWeight > 0
126→      ? Math.round(currentWeightedSum / totalWeight)
127→      : globalScore;
128→    projectedEngineScores[engine] = totalWeight > 0
129→      ? Math.round(projectedWeightedSum / totalWeight)
130→      : projectedGlobalScore;
131→  }
132→
133→  // Citation rates
134→  const currentCitationRate = estimateCitationRate(globalScore);
135→  const projectedCitationRate = estimateCitationRate(projectedGlobalScore);
136→
137→  return {
138→    projectedGlobalScore,
139→    globalScoreGain: projectedGlobalScore - globalScore,
140→    currentEngineScores,
141→    projectedEngineScores,
142→    currentCitationRate,
143→    projectedCitationRate,
144→    citationRateGain: projectedCitationRate - currentCitationRate,
145→    selectedCount: selectedSolutions.size,
146→    totalCount: recommendations.length,
147→  };
148→}
