 12→function rateColor(rate: number): string {
 13→  if (rate >= 50) return 'text-emerald-400';
 14→  if (rate >= 20) return 'text-amber-400';
 15→  if (rate > 0) return 'text-red-400';
 16→  return 'text-zinc-600';
 17→}
 18→
 19→type SupportedEngine = 'chatgpt' | 'perplexity' | 'gemini' | 'claude' | 'copilot' | 'ai_overviews';
 20→
 21→const ENGINE_BAR_COLORS: Record<SupportedEngine, string> = {
 22→  chatgpt: 'bg-emerald-500',
