 24→  gemini: 'bg-purple-500',
 25→  claude: 'bg-orange-500',
 26→  copilot: 'bg-cyan-500',
 27→  ai_overviews: 'bg-amber-500',
 28→};
 29→
 30→const ENGINE_DISPLAY: Array<{ id: SupportedEngine; label: string; dotColor: string }> = [
 31→  { id: 'chatgpt',      label: 'ChatGPT',      dotColor: 'bg-emerald-500' },
 32→  { id: 'perplexity',   label: 'Perplexity',    dotColor: 'bg-blue-500' },
