 36→  { id: 'ai_overviews', label: 'AI Overviews',  dotColor: 'bg-amber-500' },
 37→];
 38→
 39→function barColor(engine: SupportedEngine): string {
 40→  return ENGINE_BAR_COLORS[engine] || 'bg-zinc-500';
